import{_ as r,o,c as a,a9 as e}from"./chunks/framework.D4xYp1Zt.js";const p="/images/how-to-beat-procrastination/icky-list.png",n="/images/how-to-beat-procrastination/icky-task.png",s="/images/how-to-beat-procrastination/unicky-task.png",i="/images/how-to-beat-procrastination/idea-man.png",l="/images/how-to-beat-procrastination/dark-woods.png",h="/images/how-to-beat-procrastination/dark-woods-pro-good.png",c="/images/how-to-beat-procrastination/dark-woods-pro-1.png",m="/images/how-to-beat-procrastination/dark-woods-pro-2.png",g="/images/how-to-beat-procrastination/dark-woods-pro-3.png",b="/images/how-to-beat-procrastination/The-Critical-Entrance.png",A="/images/how-to-beat-procrastination/Pathways.png",w="/images/how-to-beat-procrastination/Pathways-banana.png",f="/images/how-to-beat-procrastination/dark-woods-tipping-point.png",_="/images/how-to-beat-procrastination/running.png",d="/images/how-to-beat-procrastination/happy-playground.png",u="/images/how-to-beat-procrastination/flow.png",k="/images/how-to-beat-procrastination/plushies-ad-for-post.jpg",y="/images/how-to-beat-procrastination/pinit_fg_en_rect_gray_20.png",M=JSON.parse('{"title":"How to Beat Procrastination","description":"","frontmatter":{"title":"How to Beat Procrastination","titleZh":"如何战胜拖延症","date":"2013-11-06T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html","slug":"how-to-beat-procrastination"},"headers":[],"relativePath":"posts/how-to-beat-procrastination.md","filePath":"posts/how-to-beat-procrastination.md","lastUpdated":1782886257000}'),P={name:"posts/how-to-beat-procrastination.md"};function I(q,t,T,U,G,x){return o(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="如何战胜拖延症-·-how-to-beat-procrastination" tabindex="-1">如何战胜拖延症 · How to Beat Procrastination <a class="header-anchor" href="#如何战胜拖延症-·-how-to-beat-procrastination" aria-label="Permalink to &quot;如何战胜拖延症 · How to Beat Procrastination&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html</a> · 2013-11-06</p></blockquote><h2 id="这是第二部分。如果你还没读第一部分-直接看第二部分是看不懂的。第一部分在这里。" tabindex="-1"><em>这是第二部分。如果你还没读第一部分,直接看第二部分是看不懂的。<strong><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">第一部分在这里</a>。</strong></em> <a class="header-anchor" href="#这是第二部分。如果你还没读第一部分-直接看第二部分是看不懂的。第一部分在这里。" aria-label="Permalink to &quot;*这是第二部分。如果你还没读第一部分,直接看第二部分是看不懂的。**[第一部分在这里](https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html)。***&quot;">​</a></h2><h2 id="pdf-我们做了这篇文章的精美-pdf-版本-方便打印和离线阅读。点这里购买。-或者看看预览。" tabindex="-1"><em><strong>PDF:</strong> 我们做了这篇文章的精美 PDF 版本,方便打印和离线阅读。<a href="https://gum.co/wbw-proc2" target="_blank" rel="noreferrer">点这里购买</a>。(或者看看<a href="https://waitbutwhy.com/wp-content/uploads/2016/02/how-to-beat-procrastination-preview.pdf" target="_blank" rel="noreferrer">预览</a>。)</em> <a class="header-anchor" href="#pdf-我们做了这篇文章的精美-pdf-版本-方便打印和离线阅读。点这里购买。-或者看看预览。" aria-label="Permalink to &quot;***PDF:** 我们做了这篇文章的精美 PDF 版本,方便打印和离线阅读。[点这里购买](https://gum.co/wbw-proc2)。(或者看看[预览](https://waitbutwhy.com/wp-content/uploads/2016/02/how-to-beat-procrastination-preview.pdf)。)*&quot;">​</a></h2><p><strong>pro-cras-ti-na-tion</strong> |prəˌkrastəˈnāSHən, prō-|<br> 名词<br><em>莫名其妙地毁掉自己人生的行为</em></p><p>先说一句,一边跟严重的拖延症搏斗一边写关于拖延症以及如何战胜它的文章,这种讽刺我已经受够了。过去两周我就像<a href="https://www.youtube.com/watch?v=zw-jTCNZSmY" target="_blank" rel="noreferrer">这个哥们</a>一样,一边讲枪支安全一边把自己脚打了个洞。写完这篇之后,我期待着回到没有讽刺意味的纯粹拖延状态。</p><p>开始之前先说两件事:</p><ul><li><p>我不是这方面的专家,只是一个终身拖延症患者,一直在琢磨这个话题。我现在还在跟自己的习惯激烈搏斗,但过去几年里确实取得了一点进展,我要分享的想法都是对我自己有效的东西。</p></li><li><p>这篇文章发晚了,不只是因为花了我 2000 年才写完,还因为我周一晚上突然觉得,现在有一件极其紧急的事情要做——打开 Google Earth,悬停在印度南端上方几百英尺的地方,然后一路向北滚动到印度最北端,以便「更好地感受一下印度」。我有毛病。</p></li></ul><p>好了,上周我们深入探讨了<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">拖延症患者日常内心的挣扎</a>,分析了背后的心理机制。但这周我们要真正开始做点什么,就得挖得更深。我们先来剖析一下拖延症患者的心理,看看问题的核心到底是什么:</p><p>我们已经知道即时满足猴 (Instant Gratification Monkey)(你大脑里那个让你拖延的部分)的存在,也知道它是怎么压制理性决策者 (Rational Decision Maker) 的,但那里究竟发生了什么?</p><p>拖延症患者陷入了一种坏习惯,几乎接近上瘾——他放任猴子获胜。他仍然打算控制猴子,但他所付出的努力是无力的,用的还是那些多年来被证明根本不管用的老办法,他内心深处也清楚猴子会赢。他发誓要改变,但模式一成不变。那么,一个本来有能力的人,为什么会一遍又一遍地拿出这么敷衍、这么无用的努力?</p><p>**答案是:在人生的这个部分,他极度缺乏自信,任凭自己被一个自我挫败、自我实现的预言所奴役。**我们把这个自我实现的预言叫做他的「剧本」(Storyline)。拖延症患者的剧本大概是这样的:</p><p><em>对于我生活中的「必须做」清单,我总是拖到最后一刻,慌慌张张,要么做得远低于自己的水平,要么干脆撂挑子什么都不干。而对于我生活中的「想要做」清单——说实话——我要么开个头就放弃了,要么更可能的是,压根儿就抽不出空去做。</em></p><h2 id="拖延症患者的问题根深蒂固-光靠「更自律一点」或者「改掉坏习惯」根本不足以让他改变现状——问题的根源嵌在他的故事线-storyline-里-而必须改变的正是这条故事线。" tabindex="-1">拖延症患者的问题根深蒂固,光靠「更自律一点」或者「改掉坏习惯」根本不足以让他改变现状——<strong>问题的根源嵌在他的故事线 (Storyline) 里,而必须改变的正是这条故事线。</strong> <a class="header-anchor" href="#拖延症患者的问题根深蒂固-光靠「更自律一点」或者「改掉坏习惯」根本不足以让他改变现状——问题的根源嵌在他的故事线-storyline-里-而必须改变的正是这条故事线。" aria-label="Permalink to &quot;拖延症患者的问题根深蒂固,光靠「更自律一点」或者「改掉坏习惯」根本不足以让他改变现状——**问题的根源嵌在他的故事线 (Storyline) 里,而必须改变的正是这条故事线。**&quot;">​</a></h2><p>在我们讨论故事线如何改变之前,先具体看看拖延症患者到底想变成<em>什么样</em>。正确的习惯究竟是什么样子的?拖延症患者又会在哪儿栽跟头?</p><p>要以健康且有效的方式达成目标,有两个组成部分——<strong>规划</strong>和<strong>执行</strong>。我们先从简单的说起:</p><h2 id="规划" tabindex="-1"><strong>规划</strong> <a class="header-anchor" href="#规划" aria-label="Permalink to &quot;**规划**&quot;">​</a></h2><p>拖延症患者热爱规划,原因很简单,因为规划不涉及<em>执行</em>,而执行正是拖延症患者的克星氪石 (Kryptonite)。</p><p>但拖延症患者规划的时候,喜欢用一种模糊的、不太考虑细节和现实的方式,他们的规划恰好把自己安排得完美无缺——完美到什么都干不成。拖延症患者的规划过程,给执行者留下的是一场噩梦:</p><p><strong>一张长长的、又恶心又吓人的任务清单。</strong></p><p><a href="https://2.bp.blogspot.com/-nrHAY4PEcNM/UnnTw27987I/AAAAAAAAGIU/rbOc2s7zwgM/s1600/icky+list.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>一张又长又模糊又吓人的清单,能把及时行乐猴 (Instant Gratification Monkey) 逗<em>笑</em>。当你列出这样的清单时,猴子会说:「哦太完美了,这活儿简单。」哪怕你那容易上当的意识层面真心以为自己会高效地搞定清单上的项目,猴子也知道在你的<em>潜意识</em>里,你压根就没那个打算。</p><p>而有效的规划,是把你导向<em>成功</em>的。它的目的和上一句话里的每个字都恰恰相反:</p><h4 id="有效的规划从长清单里选出一个赢家" tabindex="-1"><strong>有效的规划从长清单里选出一个赢家:</strong> <a class="header-anchor" href="#有效的规划从长清单里选出一个赢家" aria-label="Permalink to &quot;**有效的规划从长清单里选出一个赢家:**&quot;">​</a></h4><p>长清单也许是规划的早期阶段,但规划必须以严格的优先级排序作为结尾,并且<em>只有一个</em>项目脱颖而出成为赢家——那就是你要放在首位去做的项目。而胜出的那一个,应该是对你而言最有意义的——对你的幸福<em>最重要</em>的那一件。如果涉及紧急事项,那些必须排在前面,并尽快解决掉,好给重要事项腾出位置(拖延症患者最爱拿不重要但紧急的事情当借口,来无限期推迟真正重要的事)。</p><h4 id="有效的规划把恶心的任务变得不恶心" tabindex="-1"><strong>有效的规划把恶心的任务变得不恶心:</strong> <a class="header-anchor" href="#有效的规划把恶心的任务变得不恶心" aria-label="Permalink to &quot;**有效的规划把恶心的任务变得不恶心:**&quot;">​</a></h4><p>我们都知道什么叫恶心的任务。恶心的任务是模糊而混沌的,你根本不知道该从哪儿下手、该怎么做、也不知道该去哪儿找答案来解决相关的疑问。</p><p>假设你的梦想是做一个自己的 App,你知道如果做出一个成功的 App,就可以辞掉工作,成为一名全职开发者。你还觉得编程能力是 21 世纪的读写能力,而且你也没钱外包给别人开发,于是你决定给「学会编程」加冕,让它成为清单上的胜出者——头号优先级。激动吧?</p><p>嗯,并不激动,因为「学会编程」是一个极其恶心的事项——每次你决定该开始动手了,你偏偏也会同时决定收件箱得清理一下、厨房地板得马上拖一拖。这事儿永远也不会真正发生。</p><p>要给这个事项「去恶心化」,你得去阅读、调研、问问题,搞清楚一个人到底是怎么学编程的,每一步需要什么具体手段,每一步大概要花多长时间。给清单事项去恶心化,就是把它从这样:</p><p><a href="https://2.bp.blogspot.com/-HN5KKEJPKF0/UnoXNWUC1MI/AAAAAAAAGJ4/bakiABFPnqI/s1600/icky+task.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>变成这样:</p><p><a href="https://4.bp.blogspot.com/-bybtZDapIzg/UnnTxy_4onI/AAAAAAAAGJA/p3y6KvqFxE0/s1600/unicky+task.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><h4 id="有效的计划-能把一个吓人的事项变成一连串小的、清晰的、可管理的任务" tabindex="-1"><strong>有效的计划,能把一个吓人的事项变成一连串小的、清晰的、可管理的任务:</strong> <a class="header-anchor" href="#有效的计划-能把一个吓人的事项变成一连串小的、清晰的、可管理的任务" aria-label="Permalink to &quot;**有效的计划,能把一个吓人的事项变成一连串小的、清晰的、可管理的任务:**&quot;">​</a></h4><p>「恶心」和「吓人」结合起来,就是及时行乐猴 (Instant Gratification Monkey) 的类固醇魔药。而且你就算把一个事项去恶心化了,也不代表它就不再庞大和吓人。给事项「去吓人化」的关键,是吸收这个事实:</p><p><em>一个了不起的、辉煌的成就,从远处看,不过就是一长串平平无奇、毫不辉煌的小任务的样子。</em></p><p><a href="https://1.bp.blogspot.com/-lmIVWhUbvLM/UnnTxUEQEUI/AAAAAAAAGIw/z_l5Lf1zEBY/s1600/idea+man.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>没有人「盖了一栋房子」。他们只是一块砖一块砖一块砖地砌,最后的结果就是一栋房子。拖延者都是伟大的空想家——他们喜欢幻想有一天自己会拥有的美丽豪宅——但他们真正需要做的,是变成脏兮兮的建筑工人,一天又一天,一块接一块地按部就班地砌砖,不放弃,直到房子建成。</p><p>几乎每一件大工程,都可以归结为一个核心的进度单位——它的砖头。45 分钟的健身房锻炼,就是把身材练好的那块砖。30 分钟的练习,就是成为吉他高手的那块砖。</p><p>一个想当作家的人和一个真正作家的一周,平均下来的日常几乎一模一样。真作家每天写几页,砌了一块砖;想当作家的人什么也没写。他们一天中 98% 的时间其他部分几乎完全相同。但一年之后,真作家有了一本书完整的初稿,而想当作家的人有的是……啥也没有。</p><p>一切都在于那些砖头。</p><p>好消息是,砌一块砖并不吓人。但砖头需要排期。所以规划的最后一步是做一个「砖头时间表」,把砖头塞进日历里。这些时间格是不容商量、不可取消的——毕竟,这是你的头等大事,是你最看重的事情,不是吗?最重要的日期是第一个。你不能「11 月」开始学编程。但你 <em>可以</em> 在 11 月 21 号下午 6:00 – 7:00 开始学编程。</p><p>现在你已经规划好了——跟着日程走,你就会成为一名程序员。剩下的就是 <em>去做</em>……</p><h2 id="执行" tabindex="-1"><strong>执行</strong> <a class="header-anchor" href="#执行" aria-label="Permalink to &quot;**执行**&quot;">​</a></h2><p>拖延症患者不是不喜欢做事的 <em>概念</em>。他们看着日历上的砖头会想:「太好了,这肯定挺有意思。」这是因为当他们 <em>想象</em> 未来自己坐下来干完一段活儿的场景时,画面里从来没有及时行乐猴 (Instant Gratification Monkey) 的存在。拖延症患者对未来的想象里似乎永远不包括那只猴子。</p><p>但真到了动工砌砖的那一刻,拖延症患者干起了他最擅长的事——让猴子接管一切并毁掉一切。</p><p>既然我们刚刚强调过,所有成就都归结为在日程安排的那个时间格里砌下那一块砖的能力,那我们似乎已经把核心难题隔离出来了。让我们仔细看看砌一块砖这个具体挑战:</p><p><a href="https://3.bp.blogspot.com/-9nqzB5lpFZ8/UnnXYJWDgyI/AAAAAAAAGJU/TOKj4PGOpCA/s1600/dark+woods.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>所以这张图代表了你每次接手一项任务时面临的挑战,不管是做工作用的 PPT、去跑步、写剧本,还是你生活中做的任何其他事情。「关键入口」是你正式开工的地方,「黑暗森林」是你真正干活的过程,一旦干完,你就会被奖励一张进入「快乐游乐场」的门票——在那里你会感到满足,休闲时光也变得愉悦而有回报,因为你完成了一件难事。你甚至偶尔会全身心投入手头的工作,进入 <a href="https://en.wikipedia.org/wiki/Flow_(psychology)" target="_blank" rel="noreferrer">心流 (Flow)</a> 状态,在这种极乐的沉浸中忘掉时间。</p><p>这些路径大概长这样:</p><p><a href="https://4.bp.blogspot.com/-uKXCe9UmIL4/UnnTvXcmO1I/AAAAAAAAGH0/pMmVcXNXsy4/s1600/dark+woods+pro+good.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>听起来挺简单的,对吧?</p><p>嗯,不幸的是,对拖延症患者来说,他们往往既错过了「快乐游乐场」也错过了心流。</p><p>比如,这里有个拖延症患者压根就没开始做他该做的事,因为他根本迈不进「关键入口」。反而,他花了好几个小时在「黑暗游乐场」里泥足深陷,自我厌恶:</p><p><a href="https://3.bp.blogspot.com/-pWjsyJQXsL0/UnnTu8AWOsI/AAAAAAAAGHo/icgGgY2Jppo/s1600/dark+woods+pro+1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>这位拖延症患者倒是开始动手了,但她没法保持专注,一会儿跑去上网,一会儿又去弄吃的,休息一次就是老半天。最后她没能把任务做完:</p><p><a href="https://1.bp.blogspot.com/-wB4QQrzF2Kg/UnnTvKzDwtI/AAAAAAAAGH8/gpJEZtX3va8/s1600/dark+woods+pro+2.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>这位拖延症患者压根就动不了手,尽管工作截止日期越来越近,他还是在黑暗游乐场 (Dark Playground) 里泡了好几个小时,心里清楚死线迫在眉睫,不开始只会让自己更难受。终于,截止日期近到不能再近,恐慌怪兽 (Panic Monster) 突然咆哮着冲进房间,把他吓得魂飞魄散,逼着他火速赶工才勉强赶上了 deadline。</p><p><a href="https://2.bp.blogspot.com/-9IfjvZerFrM/UnnTvTaN0-I/AAAAAAAAGII/eE_e_m83nc4/s1600/dark+woods+pro+3.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""><br></a></p><p>做完之后,他感觉还行,毕竟完成了点东西,但也没那么爽,因为他知道自己因为太仓促,项目做得很平庸,而且他觉得自己一整天大部分时间都莫名其妙地拖延掉了。这让他落到了「五味杂陈公园 (Mixed Feelings Park)」。</p><p>所以如果你是个拖延症患者,让我们来看看你需要做些什么,才能走上正确的道路——一条最终会让你幸福得多的路。</p><p>你<em>必须</em>做的第一件事,就是闯过「关键入口 (Critical Entrance)」。这意味着到了该开始任务的时间,停下你手头的一切,收起所有干扰,然后开工。听起来很简单,但这是最难的一部分。及时行乐猴 (Instant Gratification Monkey) 会在这里发起最猛烈的抵抗:</p><p><a href="http://store.waitbutwhy.com/collections/posters/products/dark-playground-poster-18x24" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>这只猴子绝对<em>痛恨</em>停下好玩的事去开始做难事,这就是你需要最坚强的时刻。如果你能开始动手,把猴子逼进黑暗森林 (Dark Woods),你就已经挫掉了它一部分的意志。</p><p>当然,它不会那么快就放弃。</p><p>黑暗森林就是你干活时所处的地方。这不是个好玩的地方,及时行乐猴一点儿都不想待在这儿。更麻烦的是,黑暗森林<em>被</em>黑暗游乐场包围着——那可是猴子最爱的地方之一——它眼看着游乐场就在旁边,自然会拼了命想离开黑暗森林。</p><p>还有些时候你会一头撞上树——也许你慢跑的路突然变成了上坡,也许你得用一个你不会的 Excel 公式,也许你正在写的那首歌怎么弄都不对味——这时候猴子就会发起最大胆的逃跑尝试。</p><p><a href="https://3.bp.blogspot.com/-71NCXEczHDE/UnodcBTMo4I/AAAAAAAAGKQ/ArxNFsd6Efo/s1600/Pathways.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>离开黑暗森林却跑去黑暗游乐场,这毫无道理——两个地方都是黑的。待在哪里都难受,但最大的区别在于:黑暗森林通往幸福,而黑暗游乐场只通往更多的痛苦。可即时满足猴不讲逻辑,在它眼里,黑暗游乐场看起来好玩多了。</p><p>好消息是,只要你能硬着头皮在黑暗森林里往前推进一点点,神奇的事情就会发生。任务上有了进展,会带来正面的成就感,提升你的自尊心。而猴子的力量正是靠低自尊来滋养的,当你感受到一丝自我满足的电流时,猴子就会在路上发现一根「高自尊香蕉」。这根香蕉虽然不能完全压制它的反抗,但足以让它分心一阵子,你会发现拖延的冲动减弱了。</p><p><a href="https://3.bp.blogspot.com/-mH07JBfOjhI/UnoU9D0NSXI/AAAAAAAAGJw/UifIW7i_jM0/s1600/Pathways+banana.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>接着,如果你继续往前走,魔法就会出现。一旦你完成了任务的 2/3 或 3/4,尤其是进展顺利的话,你会突然觉得一切都棒极了,终点就在眼前。这是一个关键的转折点——</p><p><a href="https://4.bp.blogspot.com/-yfBP07jfHIA/UnnTv6bpgJI/AAAAAAAAGIE/r8390h79JL8/s1600/dark+woods+tipping+point.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>这个转折点之所以重要,是因为不只是你能闻到前方快乐游乐场的味道——<em>猴子也能闻到</em>。猴子不在乎它的即时满足是跟你一起享受还是以你为代价换来的,它只喜欢又轻松又好玩的东西。一旦过了转折点,猴子就会<em>对通往快乐游乐场比通往黑暗游乐场更感兴趣</em>。这时候,你所有拖延的冲动都会消失,你和猴子一起飞奔向终点。</p><p><a href="https://3.bp.blogspot.com/-02pghkHRbdY/UnobAjF329I/AAAAAAAAGKE/_p2dJNzhs9M/s1600/running.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>一眨眼,你就完成了,并且踏进了快乐游乐场。这时候,久违地,你和猴子成了<em>队友</em>。你们俩都想玩,而这份玩耍感觉特别爽,因为它是<em>挣来的</em>。当你和猴子站在同一队时,你几乎总是快乐的。</p><p><a href="https://4.bp.blogspot.com/-jdCzgYM0mDU/UnnTwitl0yI/AAAAAAAAGIc/doz0fT3jiSs/s1600/happy+playground.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>当你越过临界点之后,还有另一件事可能会发生——这取决于任务的类型以及进展是否顺利——你可能会开始对手头的事情感觉<em>棒极了</em>,棒到继续干下去听起来比停下来去玩休闲活动要<em>有趣得多</em>。你已经痴迷于这件事,对基本上其他一切都失去了兴趣,包括吃饭和时间——这就是所谓的心流 (Flow)。心流不仅是一种极乐的感觉,而且通常正是你做出伟大成就的时刻。</p><p>猴子和你一样也对这种极乐上瘾,你俩又成了一支团队。</p><p><a href="https://4.bp.blogspot.com/-TThDi_Enbb0/UnnTwYTi-OI/AAAAAAAAGIQ/P-AHDDevCYA/s1600/flow.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>奋力挺进到临界点已经很难了,但真正让拖延<em>如此</em>难以战胜的原因是,即时满足猴子的短期记忆糟糕得可怕——即使你在周一大获全胜,到了周二再开始一项任务时,猴子已经把一切都忘光了,又会继续抗拒进入黑暗森林或在其中前进。</p><p>这就是为什么坚持是成功如此关键的组成部分。每砌一块砖都要经历一场内心挣扎——而归根结底,你能否赢下这场非常具体的挣扎、日复一日地一块接一块砌下去,正是一个拖延者夺回对自己世界控制权的核心所在。</p><p>所以这就是需要发生的事——但如果拖延症能靠读一篇博客文章就解决,它就不会成为这么多人生活中如此巨大的问题了。真正战胜拖延症只有一种办法:</p><p><strong>你需要向自己证明你能做到。</strong></p><p>你需要向自己展示你能做到,而不是告诉自己。当你向自己展示了事情可以做到,事情才会发生改变。在那之前,你不会相信,一切都不会改变。把自己想象成一个手感冰凉的篮球运动员。对篮球运动员来说,一切都在于信心,一个手感冰点的射手可以对自己说 1000 遍「我是个伟大的射手,下一球我一定进」,但只有当他真的投进一球,他的信心才会回升,手感才会回来。</p><p>那么你要怎么开始投进球呢?</p><p><strong>1) 试着把「你做的每一件事都是一个选择」这个事实内化。</strong></p><p>先从思考这几篇文章里用到的那些词开始,如果它们让你有共鸣,就把它们写下来。我之所以给这么多感受或现象都起了名字——即时满足猴子、理性决策者、恐慌怪兽、黑暗游乐场、恶心感、砖块、关键入口、黑暗森林、临界点、快乐游乐场、心流、你的故事线——一部分原因就在于,这些词能帮你把自己正在做的选择的真实面貌看得更清楚。它有助于揭露糟糕的选择,并突出何时最该做出正确的选择。</p><p><strong>2) 创造一些帮你打败猴子的方法。</strong></p><p>一些可能的方法:</p><ul><li>寻求外部支援,把你想完成的目标告诉一个或几个朋友或家人,请他们盯着你去完成。如果因为种种原因这很难做到,那就发邮件给我——我是个陌生人 (<a href="/cdn-cgi/l/email-protection.html">[email protected]</a>)——光是把目标打出来发给一个真实的人,就能让它变得更真实一些。(有些专家认为,把目标告诉身边的人可能适得其反,所以这得看你的具体情况。)</li><li>如果还没有惊慌怪兽,就制造一个——如果你想做完一张专辑,那就把几个月后的演出档期定下来,订好场地,给一群人发出邀请。</li><li>如果你真的想创业,辞掉工作会让惊慌怪兽变成你的新室友。</li><li>如果你想坚持写博客,那就在页面顶端写上&quot;每周二更新新文章&quot;……</li><li>给自己贴便利贴,提醒自己做出正确的选择。</li><li>设个闹钟,提醒自己开始某项任务,或者提醒自己后果有多严重。</li><li>想尽一切办法减少干扰。如果电视是个大问题,就把电视卖了。如果网络是个大问题,那就再弄一台没有 Wifi 的电脑专门用来工作,工作时把手机切到飞行模式。</li><li>把自己&quot;锁进&quot;某件事里——预付一笔不可退款的定金去报课程或办会员。</li></ul><p>如果你设定的方法不管用,就改。设一个一个月后的提醒:&quot;情况变好了吗?如果没有,就换个方法。&quot;</p><p><strong>3) 追求缓慢而稳定的进步——故事线是一页一页改写的。</strong></p><p>伟大的成就是一块一块不起眼的砖头堆起来的;同样,像拖延这样根深蒂固的习惯不会一下子改变,而是靠一次一次微小的改进积累出来。记住,这一切的关键是向你自己证明你能做到,所以重点不是完美,而是<em>进步</em>。每天写一页的作者,一年后就写完了一本书。每周略有进步的拖延者,一年后就是一个焕然一新的人。</p><p>所以别去想从 A 直达 Z——先从 A 走到 B 就好。把故事线从&quot;我做任何难事都会拖延&quot;改成&quot;每周一次,我不拖延地完成一件难事&quot;。如果你能做到这一点,你就开启了一种<em>趋势</em>。我自己还是个惨兮兮的拖延者,但肯定比去年强,所以我对未来还是抱有希望的。</p><p>我为什么这么频繁地想这个话题,又为什么刚刚写了一篇 3500 字的博文来讲它?</p><p>因为战胜拖延症和掌控自己的人生是同一件事。让人幸福或不幸福的那些东西——他们的成就感和满足感、他们的自尊、他们背负的遗憾、他们可以用来陪伴亲密关系的空闲时间——都受到拖延症的严重影响。所以这件事值得被死死地认真对待,而开始改善的时机就是现在。</p><hr><p><strong>这两篇文章的后续:</strong> <a href="https://waitbutwhy.com/2015/03/procrastination-matrix.html" target="_blank" rel="noreferrer"><strong>拖延矩阵 (The Procrastination Matrix)</strong></a></p><p><strong>另外还有两篇相关文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">为什么你不应该在乎别人怎么想</a>。</strong> 你大脑另一部分正在进行的另一场挣扎。来认识一下那头猛犸象吧。</p><p><strong><a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">一个给非宗教人士的宗教</a>。</strong> 更深入地看看你大脑里那只猴子和其他动物是怎么回事。**<br> 反正它们都在毁掉你的生活了,不如干脆抱着它们一起睡吧:**</p><p><a href="http://store.waitbutwhy.com/collections/plush-toys" target="_blank" rel="noreferrer"><img src="'+k+'" alt="plushies ad for post"></a></p><hr><p>如果你喜欢 Wait But Why,请注册我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的**<a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a>**。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html&amp;description=How%20to%20Beat%20Procrastination" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p>',108)])])}const B=r(P,[["render",I]]);export{M as __pageData,B as default};
